        # Membuat kata sandi dengan panjang 8 karakter
        panjang = 8
        karakter = string.ascii_letters + string.digits + string.punctuation
        kata_sandi = ''.join(random.choice(karakter) for _ in range(panjang))
        return kata_sandi

    def cek_kuat(self, kata_sandi):
        # Mengecek kekuatan kata sandi
        kekuatan = 0
