            kekuatan += 1
        if any(char.islower() for char in kata_sandi):
            kekuatan += 1
        if any(char.isupper() for char in kata_sandi):
            kekuatan += 1
        if any(char.isdigit() for char in kata_sandi):
            kekuatan += 1
        if any(char in string.punctuation for char in kata_sandi):
            kekuatan += 1
        return kekuatan

    def simpan_kata_sandi(self, kata_sandi):
        # Simpan kata sandi ke dalam file
